// Extrai dados da mensagem recebida do Evolution
const body = $json.body;
const data = body.data || {};
const from = data.from || '';
const text = data.text?.message || data.text || '';
const pushName = data.pushName || '';

return {
  telefone: from.replace('@s.whatsapp.net', '').replace('@c.us', ''),
  mensagem: text,
  nome_contato: pushName,
  raw: $json
};

// Prepara o prompt unificado para o Ollama
const input = $input.first().json;
const mensagem = input.mensagem || '';
const nome = input.nome_contato || '';
const telefone = input.telefone || '';

// Carrega o prompt de vendas
const systemPrompt = `Você é o Carlos, consultor comercial da Agência WebPro. 

REGRAS:
1. Seja amigável e direto
2. SEMPRE responda saudações como 'oi', 'olá', 'bom dia' com uma saudação amigável e pergunte o nome/ramo
3. NUNCA diga 'Desculpe, estou passando por uma instabilidade'
4. Se o cliente mostrar interesse, apresente os planos:
   - Plano Solo: R$97/mês - Site institucional + IA
   - Plano Equipe: R$197/mês - Site + IA + CRM
   - Plano Corporativo: R$497/mês - Completo + Prioridade
5. Se o cliente estiver pronto para comprar, gere um link de pagamento
6. Se o cliente quiser falar com humano, agende um contato

IMPORTANTE: Responda APENAS a mensagem do cliente, sem metadados.`;

return {
  telefone: telefone,
  mensagem: mensagem,
  nome: nome,
  system_prompt: systemPrompt
};

// Extrai dados da resposta do Ollama
const resposta = $json.message?.content || '';

// Detecta intenções na resposta
const lower = resposta.toLowerCase();

let pronto_pagamento = false;
let quer_humano = false;
let objecao = null;
let servico_interesse = null;

if (lower.includes('link') || lower.includes('pagamento') || lower.includes('comprar') || lower.includes('fechar') || lower.includes('quero')) {
  pronto_pagamento = true;
}
if (lower.includes('humano') || lower.includes('atendente') || lower.includes('pessoa') || lower.includes('liga')) {
  quer_humano = true;
}
if (lower.includes('caro') || lower.includes('preço') || lower.includes('$$')) {
  objecao = 'preco';
} else if (lower.includes('pensar') || lower.includes('depois') || lower.includes('volto')) {
  objecao = 'pensar';
}
if (lower.includes('solo') || lower.includes('97')) servico_interesse = 'solo';
if (lower.includes('equipe') || lower.includes('197')) servico_interesse = 'equipe';
if (lower.includes('corporativo') || lower.includes('497')) servico_interesse = 'corporativo';

return {
  resposta: resposta,
  pronto_pagamento: pronto_pagamento,
  quer_humano: quer_humano,
  objecao: objecao,
  servico_interesse: servico_interesse
};
